def validate(payload):
    if 'name' not in payload or not payload['name']:
        raise ValueError('name is required')
    if not isinstance(payload['name'], str):
        raise TypeError('name must be a string')
    return True

files.test_validator.py:
import unittest

from validator import validate


class ValidatorTests(unittest.TestCase):
    def test_missing_name_rejected(self):
        with self.assertRaises(ValueError):
            validate({})

    def test_empty_name_is_present(self):
        self.assertTrue(validate({'name': ''}))

    def test_non_string_rejected(self):
        with self.assertRaises(TypeError):
            validate({'name': 3})


if __name__ == '__main__':
    unittest.main()

files.test_config_loader.py:
import unittest

from config_loader import load_port


class ConfigLoaderTests(unittest.TestCase):
    def test_default_port(self):
        self.assertEqual(load_port({}), 8000)

    def test_env_override(self):
        self.assertEqual(load_port({'APP_PORT': '9001'}), 9001)

    def test_invalid_override_uses_default(self):
        self.assertEqual(load_port({'APP_PORT': 'nope'}), 8000)


if __name__ == '__main__':
    unittest.main()

